import * as React from 'react';
import { styled } from '@mui/material/styles';
import Box from '@mui/material/Box';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import CardMedia from '@mui/material/CardMedia';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import Avatar from '@mui/material/Avatar';
import Paper from '@mui/material/Paper';
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import ListItemIcon from '@mui/material/ListItemIcon';
import ListItemText from '@mui/material/ListItemText';
import './GenericCard.scss';

// Types for different card variants
export interface GenericCardData {
  id: string;
  title: string;
  description?: string;
  image?: string;
  subtitle?: string;
  tag?: string;
  badge?: string;
  authors?: { name: string; avatar: string }[];
  metadata?: Record<string, any>;
  actions?: Array<{
    label: string;
    onClick: () => void;
    variant?: 'text' | 'outlined' | 'contained';
    color?: 'primary' | 'secondary' | 'success' | 'error' | 'info' | 'warning';
  }>;
}

export interface GenericCardProps {
  data: GenericCardData;
  variant?: 'default' | 'news' | 'service' | 'governance' | 'contact';
  size?: 'small' | 'medium' | 'large';
  onClick?: () => void;
  onFocus?: (index: number) => void;
  onBlur?: () => void;
  tabIndex?: number;
  focused?: boolean;
  className?: string;
  hideImage?: boolean;
  hideActions?: boolean;
  customContent?: React.ReactNode;
}

// Styled components based on Noticias structure
const StyledCard = styled(Card)<{ cardvariant?: string }>(({ theme, cardvariant = 'default' }) => ({
  display: 'flex',
  flexDirection: 'column',
  padding: 0,
  height: '100%',
  backgroundColor: (theme.vars || theme).palette.background.paper,
  transition: 'all 0.3s ease-in-out',
  '&:hover': {
    backgroundColor: 'transparent',
    cursor: 'pointer',
    transform: cardvariant === 'service' || cardvariant === 'governance' ? 'translateY(-4px)' : 'none',
    boxShadow: cardvariant === 'service' || cardvariant === 'governance' ? 4 : 'none',
  },
  '&:focus-visible': {
    outline: '3px solid',
    outlineColor: 'hsla(210, 98%, 48%, 0.5)',
    outlineOffset: '2px',
  },
  textAlign: 'center',
  border: '1px solid rgba(0, 0, 0, 0.08)',
}));

const StyledCardContent = styled(CardContent)({
  display: 'flex',
  flexDirection: 'column',
  gap: 4,
  padding: 16,
  flexGrow: 1,
  '&:last-child': {
    paddingBottom: 16,
  },
});

const StyledTypography = styled(Typography)({
  display: '-webkit-box',
  WebkitBoxOrient: 'vertical',
  WebkitLineClamp: 2,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
});

// Author component (from Noticias)
const Author: React.FC<{ authors: { name: string; avatar: string }[] }> = ({ authors }) => {
  return (
    <Box
      sx={{
        display: 'flex',
        flexDirection: 'row',
        gap: 2,
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '16px',
      }}
    >
      <Box sx={{ display: 'flex', flexDirection: 'row', gap: 1, alignItems: 'center' }}>
        {authors.slice(0, 3).map((author, index) => (
          <Avatar
            key={index}
            alt={author.name}
            src={author.avatar}
            sx={{ width: 24, height: 24 }}
          />
        ))}
        {authors.length > 3 && (
          <Avatar sx={{ width: 24, height: 24, fontSize: '0.75rem' }}>
            +{authors.length - 3}
          </Avatar>
        )}
      </Box>
      <Typography variant="caption" color="text.secondary">
        {authors.length} {authors.length === 1 ? 'autor' : 'autores'}
      </Typography>
    </Box>
  );
};

// Icon component for service/governance cards
const CardIcon: React.FC<{ icon?: React.ReactNode; variant?: string }> = ({ icon, variant }) => {
  if (!icon || !['service', 'governance', 'contact'].includes(variant || '')) {
    return null;
  }

  return (
    <Box
      sx={{
        display: 'flex',
        justifyContent: 'center',
        mb: 2,
        color: 'primary.main',
        fontSize: variant === 'contact' ? '48px' : '32px',
      }}
    >
      {icon}
    </Box>
  );
};

// Action buttons component
const CardActions: React.FC<{ 
  actions?: GenericCardData['actions']; 
  variant?: string;
  hideActions?: boolean;
}> = ({ actions, variant, hideActions }) => {
  if (hideActions || !actions || actions.length === 0) {
    return null;
  }

  return (
    <Box sx={{ mt: 'auto', pt: 2, display: { xs: 'flex', md: variant === 'contact' ? 'none' : 'flex' }, gap: 1, flexDirection: 'column' }}>
      {actions.map((action, index) => (
        <Button
          key={index}
          variant="contained"
          color="primary"
          onClick={action.onClick}
          fullWidth={variant === 'service' || variant === 'contact'}
          size={variant === 'contact' ? 'medium' : 'small'}
        >
          {action.label}
        </Button>
      ))}
    </Box>
  );
};

// Requirements list component (for service cards)
const RequirementsList: React.FC<{ 
  requirements?: string[]; 
  variant?: string;
}> = ({ requirements, variant }) => {
  if (!requirements || requirements.length === 0 || !['service', 'governance'].includes(variant || '')) {
    return null;
  }

  return (
    <Paper
      variant="outlined"
      sx={{ p: 2, mb: 2, backgroundColor: "grey.50" }}
    >
      <Typography
        variant="subtitle2"
        gutterBottom
        sx={{ fontWeight: "bold" }}
      >
        { variant === 'service' ? 'Requisitos:' : '' }
      </Typography>
      <List dense>
        {requirements.map((req, reqIndex) => (
          <ListItem key={reqIndex} sx={{ px: 0, py: 0.5 }}>
            <ListItemIcon sx={{ minWidth: 24 }}>
              <Box
                sx={{
                  width: 6,
                  height: 6,
                  borderRadius: "50%",
                  backgroundColor: "primary.main",
                }}
              />
            </ListItemIcon>
            <ListItemText
              primary={req}
              primaryTypographyProps={{ variant: "body2" }}
            />
          </ListItem>
        ))}
      </List>
    </Paper>
  );
};

const GenericCard: React.FC<GenericCardProps> = ({
  data,
  variant = 'default',
  size = 'medium',
  onClick,
  onFocus,
  onBlur,
  tabIndex,
  focused,
  className,
  hideImage = false,
  hideActions = false,
  customContent,
}) => {
  const handleFocus = () => {
    onFocus?.(parseInt(data.id));
  };

  const getImageHeight = () => {
    switch (size) {
      case 'small': return 120;
      case 'large': return 240;
      default: return 180;
    }
  };

  return (
    <StyledCard
      cardvariant={variant}
      className={`${className || ''} ${focused ? 'Mui-focused' : ''}`}
      onClick={onClick}
      onFocus={handleFocus}
      onBlur={onBlur}
      tabIndex={tabIndex}
    >
      {/* Card Media/Image */}
      {data.image && !hideImage && variant === 'news' && (
        <CardMedia
          component="img"
          alt={data.title}
          image={data.image}
          sx={{
            aspectRatio: "16 / 9",
            borderBottom: "1px solid",
            borderColor: "divider",
            height: getImageHeight(),
          }}
        />
      )}

      <StyledCardContent>
        {/* Icon for service/governance/contact variants */}
        <CardIcon icon={data.metadata?.icon} variant={variant} />

        {/* Badge/Tag */}
        {(data.tag || data.badge) && (
          <Typography gutterBottom variant="caption" component="div">
            {data.tag || data.badge}
          </Typography>
        )}

        {/* Subtitle */}
        {data.subtitle && (
          <Typography variant="body2" color="text.secondary" gutterBottom>
            {data.subtitle}
          </Typography>
        )}

        {/* Title */}
        <Typography 
          gutterBottom 
          variant={size === 'small' ? 'h6' : 'h5'} 
          component="h3"
          sx={{ fontWeight: 'bold' }}
        >
          {data.title}
        </Typography>

        {/* Description */}
        {data.description && (
          <StyledTypography
            variant="body2"
            color="text.secondary"
            gutterBottom
          >
            {data.description}
          </StyledTypography>
        )}

        {/* Custom Content */}
        {customContent}

        {/* Requirements List (for service/governance variants) */}
        <RequirementsList 
          requirements={data.metadata?.requirements} 
          variant={variant} 
        />

        {/* Actions */}
        <CardActions actions={data.actions} variant={variant} hideActions={hideActions} />

        {/* Authors (only for news variant) */}
        {variant === 'news' && data.authors && data.authors.length > 0 && (
          <Author authors={data.authors} />
        )}
      </StyledCardContent>
    </StyledCard>
  );
};

export default GenericCard;
